#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int count_substrings(const char *str, const char *sub) {
    int count = 0;
    int sub_len = strlen(sub);
    if (sub_len == 0) return 0;
    const char *tmp = str;
    while ((tmp = strstr(tmp, sub)) != NULL) {
        count++;
        tmp += sub_len;
    }
    return count;
}

void replace_all(char *str, const char *old_sub, const char *new_sub) {
    char *pos = str;
    int old_len = strlen(old_sub);
    int new_len = strlen(new_sub);
    while ((pos = strstr(pos, old_sub)) != NULL) {
        memmove(pos + new_len, pos + old_len, strlen(pos + old_len) + 1);
        memcpy(pos, new_sub, new_len);
        pos += new_len;
    }
}

